      "id": "a5",
      "assumption": "Solvency checks for conditional edits are out of scope for T558 and belong to T559/T561.",
      "confidence": 0.7,
      "if_wrong": "If T558 must also add min-asset checks for conditional edits, we need to implement preview_conditional_probability_edit analogous to preview_unconditional_probability_edit, which is a significant addition."
    }
